import React, { useState, useRef, useEffect } from 'react';
import Header from './components/Header';
import Footer from './components/Footer';
import InputForm from './components/InputForm';
import ResultDisplay from './components/ResultDisplay';
import LoadingSpinner from './components/LoadingSpinner';
import ReviewPage from './components/ReviewPage';
import SettingsSidebar from './components/SettingsSidebar';

import { generateWithGemini } from './services/llm/gemini';
import { generateWithOllama } from './services/llm/ollama';

const themeColors = {
  sky: { primary: '#38bdf8', secondary: '#2c3e50', light: '#e0f2fe', background: '#f0fdf4' }, // Sky 400
  emerald: { primary: '#34d399', secondary: '#064e3b', light: '#d1fae5', background: '#ecfdf5' }, // Emerald 400
  violet: { primary: '#a78bfa', secondary: '#4c1d95', light: '#ede9fe', background: '#f5f3ff' }, // Violet 400
  rose: { primary: '#fb7185', secondary: '#881337', light: '#ffe4e6', background: '#fff1f2' }, // Rose 400
  amber: { primary: '#fbbf24', secondary: '#78350f', light: '#fef3c7', background: '#fffbeb' }, // Amber 400
  indigo: { primary: '#818cf8', secondary: '#312e81', light: '#e0e7ff', background: '#eef2ff' }, // Indigo 400
  midnight: { primary: '#8b5cf6', secondary: '#0f172a', light: '#ddd6fe', background: '#f8fafc' }, // Violet 500, Slate 900
};

const App = () => {
  const [isLoading, setIsLoading] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState(null);
  const [error, setError] = useState(null);
  const [results, setResults] = useState(null);
  const [currentPage, setCurrentPage] = useState('generator');

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [settings, setSettings] = useState({
    service: 'gemini',
    geminiApiKey: '',
    geminiModel: 'gemini-3-flash-preview',
    ollamaModel: '',
    ollamaUrl: 'http://localhost:11434',
    theme: 'light',
    colorTheme: 'sky',
  });

  const [showRomaji, setShowRomaji] = useState(true);
  const [showEnglish, setShowEnglish] = useState(true);
  const isCancelledRef = useRef(false);

  useEffect(() => {
    try {
        const savedSettings = localStorage.getItem('kaiwa-renshuu-settings');
        if (savedSettings) {
            const parsedSettings = JSON.parse(savedSettings);
            // Ensure new settings have defaults if not in storage
            setSettings(prev => ({...prev, ...parsedSettings}));
        }
    } catch (e) {
        console.error("Failed to parse settings from localStorage", e);
    }
  }, []);

  useEffect(() => {
    if (settings.theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [settings.theme]);

  // Apply color theme
  useEffect(() => {
    const colors = themeColors[settings.colorTheme] || themeColors.sky;
    const root = document.documentElement;
    root.style.setProperty('--color-primary', colors.primary);
    root.style.setProperty('--color-secondary', colors.secondary);
    root.style.setProperty('--color-light', colors.light);
    root.style.setProperty('--color-background', colors.background);
  }, [settings.colorTheme]);

  const handleSaveSettings = (newSettings) => {
    setSettings(newSettings);
    try {
        localStorage.setItem('kaiwa-renshuu-settings', JSON.stringify(newSettings));
    } catch (e) {
        console.error("Failed to save settings to localStorage", e);
    }
    setIsSettingsOpen(false);
  };

  const handleStop = () => {
    isCancelledRef.current = true;
    setLoadingMessage("Stopping generation...");
  };

  const handleDeleteResult = (indexToDelete) => {
    setResults(prevResults => (prevResults || []).filter((_, index) => index !== indexToDelete));
  };

  const handleExportAll = () => {
    if (!results || results.length === 0) return;

    const slugify = (text) => {
      return text
        .toLowerCase()
        .trim()
        .replace(/[^ \p{L}\p{N}]+/gu, '')
        .replace(/\s+/g, '-')
        .slice(0, 50);
    };

    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0'); // Months are 0-indexed
    const day = String(now.getDate()).padStart(2, '0');
    const datePrefix = `${year}${month}${day}`;

    const firstWordSlug = slugify(results[0].wordDetails.romaji || 'session');
    const fileName = `${datePrefix}-kaiwa-renshuu-session-${firstWordSlug}.json`;

    const jsonString = JSON.stringify(results, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);

    const a = document.createElement('a');
    a.href = url;
    a.download = fileName;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleGenerate = async (words, scenario) => {
    if (settings.service === 'gemini' && !settings.geminiApiKey) {
        setError("Gemini is selected, but the API Key is missing. Please add it in the Settings sidebar.");
        return;
    }
    if (settings.service === 'ollama' && (!settings.ollamaUrl || !settings.ollamaModel)) {
      setError("Ollama is selected, but the server URL is missing or no model is selected. Please configure it in Settings.");
      return;
    }

    isCancelledRef.current = false;
    setIsLoading(true);
    setError(null);
    setResults([]);

    for (let i = 0; i < words.length; i++) {
      if (isCancelledRef.current) {
        setError(prevError => (prevError ? `${prevError}\n` : '') + 'Generation stopped by user.');
        break;
      }

      const word = words[i];
      try {
        setLoadingMessage(words.length > 1 ? `Generating ${i + 1} of ${words.length}: "${word}"` : `Generating content for "${word}"...`);

        let generatedResult;
        if (settings.service === 'gemini') {
            generatedResult = await generateWithGemini(settings.geminiModel, word, scenario, settings.geminiApiKey);
        } else {
            generatedResult = await generateWithOllama(settings.ollamaModel, word, scenario, settings.ollamaUrl);
        }

        setResults(prevResults => [...(prevResults || []), generatedResult]);
      } catch (err) {
        const errorMessage = err instanceof Error ? err.message : 'An unexpected error occurred.';
        setError(prevError => 
            (prevError ? `${prevError}\n` : '') + `Failed on "${word}": ${errorMessage}`
        );
      }
    }

    setIsLoading(false);
    setLoadingMessage(null);
  };

  const visibilityButtonStyle = "py-2 px-4 rounded-md border shadow-sm text-sm font-medium focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary transition-colors";
  const activeVisibilityStyle = "bg-primary text-white border-primary";
  const inactiveVisibilityStyle = "bg-white dark:bg-slate-700 text-slate-700 dark:text-slate-200 border-slate-300 dark:border-slate-600 hover:bg-slate-50 dark:hover:bg-slate-600";

  return (
    <div className="min-h-screen flex flex-col font-sans">
      <Header currentPage={currentPage} setCurrentPage={setCurrentPage} onOpenSettings={() => setIsSettingsOpen(true)} />
      <SettingsSidebar 
        isOpen={isSettingsOpen}
        onClose={() => setIsSettingsOpen(false)}
        onSave={handleSaveSettings}
        currentSettings={settings}
      />
      <main className="flex-grow container mx-auto p-4 md:p-8">
        {currentPage === 'generator' && (
          <>
            <InputForm onGenerate={handleGenerate} isLoading={isLoading} llmConfig={settings} />

            {isLoading && (
              <div className="text-center mt-8">
                <LoadingSpinner message={loadingMessage} />
                <button
                    onClick={handleStop}
                    className="mt-4 py-2 px-6 bg-red-600 text-white font-semibold rounded-lg shadow-md hover:bg-red-700 focus:outline-none focus:ring-2 focus:ring-red-500 focus:ring-opacity-75 transition-colors"
                >
                    Stop Generation
                </button>
              </div>
            )}

            {error && (
              <div className="mt-8 bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded-lg relative max-w-2xl mx-auto dark:bg-red-900/50 dark:border-red-500/80 dark:text-red-400" role="alert">
                <strong className="font-bold">Error: </strong>
                <span className="block sm:inline whitespace-pre-wrap">{error}</span>
              </div>
            )}

            {results && results.length > 0 && (
              <div className="max-w-4xl mx-auto mt-8 flex justify-between items-center">
                  <div className="flex items-center gap-2">
                    <span className="text-sm font-medium text-slate-600 dark:text-slate-300">Show:</span>
                    <button
                      onClick={() => setShowRomaji(prev => !prev)}
                      className={`${visibilityButtonStyle} ${showRomaji ? activeVisibilityStyle : inactiveVisibilityStyle}`}
                      aria-pressed={showRomaji}
                    >
                      Romaji
                    </button>
                    <button
                      onClick={() => setShowEnglish(prev => !prev)}
                      className={`${visibilityButtonStyle} ${showEnglish ? activeVisibilityStyle : inactiveVisibilityStyle}`}
                      aria-pressed={showEnglish}
                    >
                      English
                    </button>
                  </div>
                  <button
                    onClick={handleExportAll}
                    className="bg-secondary dark:bg-primary text-white py-2 px-4 rounded-md hover:bg-slate-700 dark:hover:bg-sky-600 transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-secondary dark:focus:ring-primary inline-flex items-center gap-2 shadow-md"
                    aria-label="Export All Results to JSON"
                    title="Export All Results to JSON"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                    </svg>
                    Export All Results
                  </button>
              </div>
            )}
            {results && results.length > 0 && results.map((result, index) => (
              <ResultDisplay 
                key={index} 
                result={result} 
                showRomaji={showRomaji} 
                showEnglish={showEnglish} 
                onDelete={handleDeleteResult}
                index={index}
              />
            ))}
          </>
        )}
        {currentPage === 'review' && <ReviewPage />}
      </main>
      <Footer />
    </div>
  );
};

export default App;

import React from 'react';

// This component parses a string with furigana annotations and renders it using <ruby> tags.
const Furigana = ({ text }) => {
  // Regex to find patterns like `漢字[かんじ]` or `食[た]べます`
  const regex = /([\u4e00-\u9faf]+)\[(.+?)\]/g;
  const parts = [];
  let lastIndex = 0;
  let match;

  while ((match = regex.exec(text)) !== null) {
    // Push the text before the match
    if (match.index > lastIndex) {
      parts.push(text.substring(lastIndex, match.index));
    }
    // Push the ruby element
    const [_, kanji, furigana] = match;
    parts.push(<ruby key={match.index} className="ruby">{kanji}<rt>{furigana}</rt></ruby>);
    lastIndex = regex.lastIndex;
  }

  // Push any remaining text after the last match
  if (lastIndex < text.length) {
    parts.push(text.substring(lastIndex));
  }

  return <>{parts.map((part, i) => <React.Fragment key={i}>{part}</React.Fragment>)}</>;
};


const ConversationCard = ({ conversation, index, showRomaji, showEnglish }) => {
  return (
    <div className="bg-white dark:bg-slate-700 rounded-lg shadow-md overflow-hidden transition-shadow hover:shadow-xl">
      <div className="bg-secondary text-white p-4">
        <h3 className="text-lg font-bold font-jp">会話 {index + 1}: {conversation.title}</h3>
      </div>
      <div className="p-4 space-y-4">
        {conversation.dialogue.map((line, lineIndex) => (
          <div key={lineIndex} className="flex items-start space-x-3">
            <div className="flex-shrink-0 h-10 w-10 rounded-full bg-light dark:bg-sky-900 flex items-center justify-center text-primary font-bold">
              {line.speaker.charAt(0)}
            </div>
            <div className="flex-grow">
              <p className="font-semibold text-primary">{line.speaker}</p>
              <p className="font-jp text-slate-800 dark:text-slate-200 text-3xl leading-relaxed">
                <Furigana text={line.japanese} />
              </p>
              {showRomaji && <p className="text-3xl text-slate-500 dark:text-slate-400 italic mt-2">{line.romaji}</p>}
              {showEnglish && <p className="text-3xl text-slate-600 dark:text-slate-300 mt-1">"{line.english}"</p>}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default ConversationCard;

import React, { useState, useEffect, useRef } from 'react';
import { fetchOllamaModels } from '../services/llm/ollama';

const SettingsSidebar = ({ isOpen, onClose, onSave, currentSettings }) => {
  const [settings, setSettings] = useState(currentSettings);
  const [ollamaModels, setOllamaModels] = useState([]);
  const [isFetchingModels, setIsFetchingModels] = useState(false);
  const [fetchError, setFetchError] = useState(null);
  const [importError, setImportError] = useState(null);
  const fileInputRef = useRef(null);

  // A list of recommended Gemini models for this application
  const geminiModelOptions = [
    'gemini-3-flash-preview',
    'gemini-3-pro-preview',
    'gemini-2.5-flash',
    'gemini-2.5-flash-lite-latest',
  ];

  useEffect(() => {
    setSettings(currentSettings);
  }, [currentSettings, isOpen]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setSettings(prev => ({ ...prev, [name]: value }));
  };

  const handleServiceChange = (service) => {
    setSettings(prev => ({ ...prev, service }));
  }

  const handleThemeChange = (theme) => {
    setSettings(prev => ({ ...prev, theme }));
  }

  const handleColorThemeChange = (colorTheme) => {
    setSettings(prev => ({ ...prev, colorTheme }));
  }

  const handleSave = () => {
    onSave(settings);
  };

  const handleFetchModels = async () => {
    setIsFetchingModels(true);
    setFetchError(null);
    setOllamaModels([]);
    try {
      const models = await fetchOllamaModels(settings.ollamaUrl);
      if (models.length > 0) {
        setOllamaModels(models);
        // If no model is selected yet, or the current one is not in the list, select the first one.
        if (!settings.ollamaModel || !models.includes(settings.ollamaModel)) {
            setSettings(prev => ({...prev, ollamaModel: models[0]}));
        }
      } else {
        setFetchError("No models found. Ensure Ollama is running and has models installed (e.g., 'ollama pull llama3').");
      }
    } catch (error) {
      console.error("Failed to fetch Ollama models:", error);
      setFetchError("Could not connect to Ollama server at the specified URL.");
    } finally {
      setIsFetchingModels(false);
    }
  };

  const handleExportSettings = () => {
    setImportError(null);
    try {
        const jsonString = JSON.stringify(settings, null, 2);
        const blob = new Blob([jsonString], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = 'kaiwa-renshuu-settings.json';
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    } catch (error) {
        console.error("Failed to export settings:", error);
        setImportError("An error occurred during export.");
    }
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setImportError(null);
    const reader = new FileReader();
    reader.onload = (event) => {
        try {
            const text = event.target?.result;
            if (typeof text !== 'string') {
                throw new Error("Could not read file content.");
            }
            const importedSettings = JSON.parse(text);

            if (importedSettings && importedSettings.service && ['gemini', 'ollama'].includes(importedSettings.service)) {
                // Merge with current settings to ensure all keys exist
                setSettings(prev => ({...prev, ...importedSettings}));
            } else {
                throw new Error("Invalid or incomplete settings file.");
            }
        } catch (err) {
            setImportError(err instanceof Error ? err.message : "Failed to parse the JSON file.");
        }
    };
    reader.onerror = () => {
        setImportError("Error reading the file.");
    }
    reader.readAsText(file);

    if (fileInputRef.current) {
        fileInputRef.current.value = '';
    }
  };

  if (!isOpen) {
    return null;
  }

  const baseRadioStyle = "flex items-center justify-center w-full px-4 py-3 text-sm font-medium border rounded-lg cursor-pointer transition-all";
  const activeRadioStyle = "bg-primary text-white border-primary shadow-md";
  const inactiveRadioStyle = "bg-white text-slate-700 border-slate-200 hover:bg-slate-50 hover:border-slate-300 dark:bg-slate-700 dark:text-slate-300 dark:border-slate-600 dark:hover:bg-slate-600";

  const colorOptions = [
      { id: 'sky', color: '#38bdf8', label: 'Sky' },
      { id: 'emerald', color: '#34d399', label: 'Emerald' },
      { id: 'violet', color: '#a78bfa', label: 'Violet' },
      { id: 'rose', color: '#fb7185', label: 'Rose' },
      { id: 'amber', color: '#fbbf24', label: 'Amber' },
      { id: 'indigo', color: '#818cf8', label: 'Indigo' },
      { id: 'midnight', color: '#8b5cf6', label: 'Midnight' },
  ];

  return (
    <>
        <div 
            className="fixed inset-0 bg-black bg-opacity-50 z-40 transition-opacity"
            onClick={onClose}
            aria-hidden="true"
        ></div>
        <div className="fixed top-0 right-0 h-full w-full max-w-md bg-background dark:bg-slate-900 z-50 shadow-2xl transform transition-transform duration-300 ease-in-out"
             style={{ transform: isOpen ? 'translateX(0)' : 'translateX(100%)' }}
             role="dialog"
             aria-modal="true"
             aria-labelledby="settings-title"
        >
            <div className="flex flex-col h-full">
                <header className="p-4 border-b bg-white dark:bg-slate-800 dark:border-slate-700">
                    <div className="flex justify-between items-center">
                        <h2 id="settings-title" className="text-xl font-bold text-slate-800 dark:text-slate-200">Settings</h2>
                        <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-200 dark:hover:bg-slate-700" aria-label="Close settings">
                           <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-slate-600 dark:text-slate-300" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                        </button>
                    </div>
                </header>
                <div className="p-6 flex-grow overflow-y-auto space-y-6">
                    <fieldset>
                        <legend className="text-lg font-semibold text-slate-800 dark:text-slate-200 mb-3">Appearance</legend>
                        <div className="space-y-4">
                            <div className="grid grid-cols-2 gap-4">
                                <button onClick={() => handleThemeChange('light')} className={`${baseRadioStyle} ${settings.theme === 'light' ? activeRadioStyle : inactiveRadioStyle}`}>Light Mode</button>
                                <button onClick={() => handleThemeChange('dark')} className={`${baseRadioStyle} ${settings.theme === 'dark' ? activeRadioStyle : inactiveRadioStyle}`}>Dark Mode</button>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">Color Theme</label>
                                <div className="flex flex-wrap gap-3">
                                    {colorOptions.map((option) => (
                                        <button
                                            key={option.id}
                                            onClick={() => handleColorThemeChange(option.id)}
                                            className={`w-10 h-10 rounded-full border-2 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary ${settings.colorTheme === option.id ? 'border-slate-600 dark:border-white ring-2 ring-primary' : 'border-transparent'}`}
                                            style={{ backgroundColor: option.color }}
                                            title={option.label}
                                            aria-label={`Select ${option.label} theme`}
                                        >
                                            {settings.colorTheme === option.id && (
                                                 <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 mx-auto text-white drop-shadow-md" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                                                </svg>
                                            )}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </fieldset>

                    <fieldset>
                        <legend className="text-lg font-semibold text-slate-800 dark:text-slate-200 mb-3">Language Model</legend>
                        <div className="grid grid-cols-2 gap-4">
                            <button onClick={() => handleServiceChange('gemini')} className={`${baseRadioStyle} ${settings.service === 'gemini' ? activeRadioStyle : inactiveRadioStyle}`}>Google Gemini</button>
                            <button onClick={() => handleServiceChange('ollama')} className={`${baseRadioStyle} ${settings.service === 'ollama' ? activeRadioStyle : inactiveRadioStyle}`}>Ollama (Local)</button>
                        </div>
                    </fieldset>

                    {settings.service === 'gemini' && (
                        <div className="p-4 border rounded-lg bg-white dark:bg-slate-800/50 dark:border-slate-700 space-y-3">
                             <h3 className="font-semibold text-slate-700 dark:text-slate-300">Gemini Configuration</h3>
                             <div>
                                <label htmlFor="geminiApiKey" className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Google Gemini API Key</label>
                                <input
                                    type="password"
                                    id="geminiApiKey"
                                    name="geminiApiKey"
                                    value={settings.geminiApiKey}
                                    onChange={handleChange}
                                    className="w-full px-3 py-2 border border-slate-300 rounded-md shadow-sm focus:ring-primary focus:border-primary text-sm bg-white dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                                    placeholder="Enter your API key"
                                />
                                <p className="text-xs text-slate-500 dark:text-slate-400 mt-1">Your key is stored only in your browser's local storage.</p>
                             </div>
                             <div>
                                <label htmlFor="geminiModel" className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Select a Model</label>
                                <select
                                    id="geminiModel"
                                    name="geminiModel"
                                    value={settings.geminiModel}
                                    onChange={handleChange}
                                    className="w-full px-3 py-2 border border-slate-300 rounded-md shadow-sm focus:ring-primary focus:border-primary text-sm bg-white dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                                >
                                    {geminiModelOptions.map(model => <option key={model} value={model}>{model}</option>)}
                                </select>
                                <p className="text-xs text-slate-500 dark:text-slate-400 mt-1">Only recommended models are shown. More may be added later.</p>
                             </div>
                        </div>
                    )}

                    {settings.service === 'ollama' && (
                        <div className="p-4 border rounded-lg bg-white dark:bg-slate-800/50 dark:border-slate-700 space-y-4">
                             <h3 className="font-semibold text-slate-700 dark:text-slate-300">Ollama Configuration</h3>
                            <div>
                                <label htmlFor="ollamaUrl" className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Ollama Server URL</label>
                                <input
                                    type="text"
                                    id="ollamaUrl"
                                    name="ollamaUrl"
                                    value={settings.ollamaUrl}
                                    onChange={handleChange}
                                    className="w-full px-3 py-2 border border-slate-300 rounded-md shadow-sm focus:ring-primary focus:border-primary text-sm bg-white dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                                    placeholder="http://localhost:11434"
                                />
                            </div>
                            <div className="flex items-end gap-3">
                                <div className="flex-grow">
                                    <label htmlFor="ollamaModel" className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Select a Model</label>
                                    <select
                                        id="ollamaModel"
                                        name="ollamaModel"
                                        value={settings.ollamaModel}
                                        onChange={handleChange}
                                        disabled={ollamaModels.length === 0 || isFetchingModels}
